// كلمات يتم تجاهلها أثناء التطبيع
const ignoreWords = [
  "tax", "ticaret", "ve", "company", "ltd", "firmasi",
  "overseas", "pazarlama", "dis", "ithalat", "halinde",
  "antreas", "poliklinigi", "group", "smart",
  "2025", "2024", "2023", "kdv", "thk", "subat", "mart", "nisan", "ay"
];

// دالة التطبيع
function normalize(text) {
  return (text || "")
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "") // remove accents
    .replace(/ğ/g, "g")
    .replace(/ü/g, "u")
    .replace(/ş/g, "s")
    .replace(/ı/g, "i")
    .replace(/ö/g, "o")
    .replace(/ç/g, "c")
    .replace(/[^a-z0-9\s]/g, " ") // remove special chars
    .split(" ")
    .filter(w => w && !ignoreWords.includes(w))
    .filter((v, i, a) => a.indexOf(v) === i) // remove duplicates
    .join(" ")
    .trim();
}

// دالة حساب نسبة التشابه البسيطة (Token overlap)
function similarity(a, b) {
  const tokensA = new Set(a.split(" "));
  const tokensB = new Set(b.split(" "));
  const intersection = [...tokensA].filter(x => tokensB.has(x));
  const union = new Set([...tokensA, ...tokensB]);
  return union.size === 0 ? 0 : intersection.length / union.size;
}

// فصل الفولدرات عن الملفات
const folders = [];
const documents = [];

for (const item of items) {
  const json = item.json;

  // الفولدر
  if (json.normName && !json.fileNormName) {
    folders.push({
      id: json.id,
      norm: normalize(json.normName),
      name: json.name || ""
    });
  }

  // الملف
  if (json.fileNormName) {
    documents.push(json);
  }
}

const results = [];

for (const doc of documents) {
  const docNorm = normalize(doc.fileNormName);

  let bestFolder = null;
  let bestScore = 0;

  for (const folder of folders) {
    const score = similarity(docNorm, folder.norm);
    if (score > bestScore) {
      bestScore = score;
      bestFolder = folder;
    }
  }

  let folderId = "";
  let folderName = "";

  if (bestFolder && bestScore >= 0.65) {
    folderId = bestFolder.id;
    folderName = bestFolder.name;
    console.log(`✅ Matched: [${doc.fileNormName}] → [${bestFolder.name}] | Score: ${bestScore}`);
  } else {
    console.log(`❌ No match for [${doc.fileNormName}] | Norm: [${docNorm}] | Best Score: ${bestScore}`);
  }

  results.push({
    documentId: doc.id || "",
    documentName: doc.name || "",
    companyName: (doc.companyName || "").replace(/^TAX\s+/i, "").trim(),
    month: doc.month || "",
    year: doc.year || "",
    taxType: doc.taxType || "",
    taxTypeFull: doc.taxTypeFull || "",
    folderId: folderId,
    folderName: folderName
  });
}

return results.map(r => ({ json: r }));

